const { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType,
        BorderStyle, PageNumber, Footer, TabStopType, TabStopPosition,
        LevelFormat, ShadingType, WidthType, TableRow, TableCell, Table } = require('docx');
const fs = require('fs');

// ── 색상 상수 ─────────────────────────────────────────────────
const NAVY   = '1B2A4A';
const BLUE   = '2A5FA5';
const CORAL  = 'C0392B';
const GRAY   = '5F6368';
const LGRAY  = 'F4F4F2';
const MID    = 'D8D8D4';
const WHITE  = 'FFFFFF';

// ── 헬퍼: 단락 ───────────────────────────────────────────────
function body(text, opts = {}) {
  return new Paragraph({
    alignment: AlignmentType.JUSTIFIED,
    spacing: { after: 160, line: 340 },
    children: [new TextRun({
      text, font: 'Georgia', size: 24,
      color: opts.color || '1a1a1a',
      bold: opts.bold || false,
      italics: opts.italic || false,
    })]
  });
}

function quote(text) {
  return new Paragraph({
    alignment: AlignmentType.JUSTIFIED,
    spacing: { before: 120, after: 120, line: 320 },
    indent: { left: 720, right: 360 },
    border: { left: { style: BorderStyle.SINGLE, size: 18, color: CORAL, space: 12 } },
    children: [new TextRun({ text, font: 'Georgia', size: 22, italics: true, color: CORAL })]
  });
}

function space(n = 1) {
  return Array.from({ length: n }, () => new Paragraph({
    spacing: { after: 0, before: 0, line: 240 },
    children: [new TextRun({ text: '', size: 24 })]
  }));
}

function divider() {
  return new Paragraph({
    spacing: { before: 200, after: 200 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 4, color: MID, space: 1 } },
    children: [new TextRun({ text: '', size: 4 })]
  });
}

function label(text) {
  return new Paragraph({
    spacing: { before: 320, after: 80 },
    children: [new TextRun({
      text: text.toUpperCase(),
      font: 'Arial', size: 18, bold: true,
      color: BLUE, characterSpacing: 60
    })]
  });
}

function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 480, after: 160 },
    children: [new TextRun({ text, font: 'Arial', size: 36, bold: true, color: NAVY })]
  });
}

function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 320, after: 120 },
    children: [new TextRun({ text, font: 'Arial', size: 28, bold: true, color: BLUE })]
  });
}

function bullet(text, bold_prefix = '') {
  const children = [];
  if (bold_prefix) {
    children.push(new TextRun({ text: bold_prefix + ' ', font: 'Georgia', size: 24, bold: true, color: NAVY }));
    children.push(new TextRun({ text, font: 'Georgia', size: 24, color: '1a1a1a' }));
  } else {
    children.push(new TextRun({ text, font: 'Georgia', size: 24, color: '1a1a1a' }));
  }
  return new Paragraph({
    numbering: { reference: 'bullets', level: 0 },
    spacing: { after: 100, line: 320 },
    children
  });
}

// ── 커버 섹션 ─────────────────────────────────────────────────
const cover = [
  new Paragraph({
    spacing: { before: 1440, after: 80 },
    children: [new TextRun({
      text: 'EX INTELLIGENCE', font: 'Arial', size: 52, bold: true,
      color: NAVY, characterSpacing: 120
    })]
  }),
  new Paragraph({
    spacing: { after: 60 },
    children: [new TextRun({
      text: 'Working Backwards Essay', font: 'Arial', size: 32,
      color: BLUE, italics: true
    })]
  }),
  new Paragraph({
    spacing: { after: 40 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 6, color: CORAL, space: 1 } },
    children: [new TextRun({ text: '', size: 4 })]
  }),
  ...space(1),
  new Paragraph({
    spacing: { after: 60 },
    children: [new TextRun({
      text: '조직 건강도에서 의사결정 인텔리전스로',
      font: 'Georgia', size: 28, italics: true, color: GRAY
    })]
  }),
  new Paragraph({
    spacing: { after: 40 },
    children: [new TextRun({
      text: '데이터 수집을 넘어, 조직이 자기 자신을 현재 시제로 이해하는 능력에 대하여.',
      font: 'Georgia', size: 22, color: GRAY, italics: true
    })]
  }),
  ...space(6),
  new Paragraph({
    spacing: { after: 40 },
    children: [new TextRun({ text: '2026년 4월', font: 'Arial', size: 20, color: GRAY })]
  }),
  new Paragraph({
    spacing: { after: 40 },
    children: [new TextRun({ text: 'EXG 조직문화 · 구성원경험 담당', font: 'Arial', size: 20, color: GRAY })]
  }),
];

// ── 본문 ──────────────────────────────────────────────────────
const essay = [

  // ═══ PART 0: Working Backwards 서문 ═══
  h1('시작: 2년 후 우리는 무엇을 보고하고 있을까'),
  label('Working Backwards — 미래로부터 역산하기'),
  body('2028년, 우리 조직의 분기 경영 보고서에는 이런 문장이 등장한다.'),
  ...space(1),
  quote('"번아웃 조기 신호가 3개 조직에서 동시 감지되어 해당 팀장에게 맞춤형 케어 가이드가 발송되었으며, 2주 후 에너지 회복 지수가 평균 18포인트 상승했습니다. 이번 분기 핵심 인재 이탈률은 전년 동기 대비 22% 감소했습니다."'),
  ...space(1),
  body('이 문장이 가능하려면 지금 우리는 무엇을 설계하고 있어야 하는가. Working Backwards 방법론은 아마존이 제품 출시 전에 반드시 쓰는 프레스 릴리즈에서 유래했다. 완성된 미래를 먼저 선명하게 그리고, 그 미래로부터 역산하여 지금의 과제를 정의하는 방식이다. EX Intelligence 프로젝트는 바로 그 방식으로 설계되고 있다.'),
  body('이 에세이는 그 역산의 기록이다. 우리가 어디서 출발했고, 무엇을 발견했으며, 지금 어떤 설계에 도달해 있는지를 하나의 서사로 연결한다.'),

  divider(),

  // ═══ PART 1: 문제 정의 ═══
  h1('1. 문제: 조직은 갑자기 무너지지 않는다'),
  label('The Hidden Risk Zone'),
  body('사람이 갑자기 팀을 떠나거나, 팀이 갑자기 분열되는 일은 드물다. 대부분의 균열은 훨씬 이전부터 시작된다. 말수가 줄고, 관계성이 약해지고, 업무 의미감이 서서히 옅어진다. 그런데 그 시기에 연간 조직 건강도 설문의 응답은 여전히 "보통"이다.'),
  body('이것이 우리가 직면한 핵심 문제다. 오늘날 조직 건강도 관리의 실패는 데이터의 부족이 아니라, 시간의 지체와 해석의 실패에 있다. 위기가 가시화된 뒤에야 신호를 읽는 구조로는, 사전 개입이 원천적으로 불가능하다.'),
  body('Gallup 2025 Global Report는 이 비용을 수치로 제시한다. 글로벌 직원 몰입도는 21%에 머물고, 비몰입이 낳는 생산성 손실은 연간 4380억 달러로 추정된다. 팀 몰입도 변동의 70%가 매니저에 의해 설명된다는 사실은, 문제가 개인의 기분이 아니라 관리와 의사결정의 구조적 방치에서 비롯된다는 것을 의미한다.'),
  body('더 결정적인 데이터가 있다. Deloitte 2024 보고서에 따르면, "조직이 인간 지속가능성을 충분히 진전시키고 있는가"라는 질문에 C레벨의 82%가 "그렇다"고 답했지만, 현업 직원의 응답은 56%에 그쳤다. 26%포인트의 인식 격차. 이것이 우리가 좁혀야 할 거리다. EX Intelligence가 줄이려는 것은 점수의 격차 이전에, 인식의 지연과 판단의 거리다.'),

  divider(),

  // ═══ PART 2: 관점의 전환 ═══
  h1('2. 관점의 전환: 진단에서 인텔리전스로'),
  label('CIA의 Need to Know 원칙'),
  body('이 프로젝트의 이름이 EX "Intelligence"인 데는 이유가 있다. 인텔리전스는 단순한 데이터 수집이 아니다. CIA의 Need to Know 원칙이 그 본질을 정확히 표현한다. "결정이 필요한 사람에게, 필요한 정보를, 필요한 시점에."'),
  body('기존 조직 진단 시스템과 EX Intelligence의 차이는 네 가지 축에서 분명해진다. 주기는 연 1회 스냅샷에서 월·분기별 연속 펄스로, 목적은 데이터 저장과 전사 점수 산출에서 결정 생성과 행동 촉발로, 초점은 과거에 무엇이 문제였는가에서 현재 문제가 어디서 시작되고 있는가로, 그리고 그것을 표현하는 은유는 지난 계절의 지도에서 현재 시제의 레이더로 전환된다.'),
  body('같은 데이터라도 역할에 따라 해석의 단위가 달라져야 한다. EX Intelligence Engine은 세 수요자에게 각각 다른 질문에 대한 답을 제공한다. 리더에게는 "누가 지금 먼저 케어가 필요한가"라는 팀원 케어 우선순위와 1:1 토픽을, 경영진에게는 "어느 조직에 자원을 우선 배분해야 하는가"라는 전사 조직 건강 포트폴리오를, HR에게는 "언제, 어느 강도로 개입해야 하는가"라는 위험 집단 조기 이상 알림을. 모든 정보를 모두에게 보여주면 아무도 행동하지 못한다.'),

  divider(),

  // ═══ PART 3: 보고 피드백과 재설계 ═══
  h1('3. 재설계: 보고 피드백이 가리킨 것'),
  label('회의록이 담고 있던 진짜 질문들'),
  body('첫 번째 보고 이후 돌아온 피드백은 표면적으로는 수정 요청이었지만, 본질은 더 깊은 질문을 담고 있었다. 설문 문항을 재검토하라는 요청은 "펄스서베이"라는 방법론이 목적보다 앞서 있다는 진단이었다. 결과 활용도를 높이라는 요청은 "이 시스템으로 무엇을 할 것인가"에 대한 답이 아직 충분하지 않다는 지적이었다.'),
  body('이 피드백들이 공통으로 가리킨 것은 하나였다. 시스템의 정당성(legitimacy)에 대한 공유된 언어가 아직 없다. 구성원이 참여하지 않거나 관리자가 결과를 서랍에 넣어두는 것은, 대부분 "이게 왜 필요한지"에 대한 내면화가 되어 있지 않기 때문이다.'),

  h2('펄스 이전에 전체 지도가 먼저다'),
  body('가장 근본적인 재설계 방향은 이것이었다. 방법론의 그릇(펄스서베이)을 먼저 놓고 내용을 채우는 것이 아니라, "우리가 구성원에 대해 알아야 할 것들의 전체 지도"를 먼저 그리는 것. 그 다음, 각 항목에 가장 적합한 측정 방식을 매핑하는 순서로.'),
  body('펄스서베이는 시간 민감성이 높은 신호를 잡는 특정 도구다. 분기 1회 심층 설문으로는 절대 포착할 수 없는 신호들 — 번아웃의 초기 징후, 리더십 신뢰의 균열, AX 변화 저항의 누적 — 이것들이 펄스의 존재 이유다. 이 시간 민감성을 설명하지 않은 채 "펄스를 합시다"라고 하면, 그것은 방법론의 제안이지 필요성의 설득이 아니다.'),

  h2('이론 언어를 현실 언어로'),
  body('측정 항목 분류 체계도 전면 재설계했다. 이전 버전은 SDT, JD-R, LMX, POS 등 이론 프레임워크 기반으로 영역을 구분했다. 이것은 HR 설계자의 언어다. 경영진과 팀장은 이 언어로 읽지 않는다.'),
  body('재설계 원칙은 단순했다. 현상 서술형 언어, 즉 조직에서 실제로 들리는 목소리로 이슈를 분류한다. 그 결과 도출된 여덟 가지 현실 이슈 클러스터가 EX Intelligence의 측정 철학을 구성한다.'),

  ...space(1),
  quote('"사람들이 조용히 타고 있다" / "팀장을 믿지 못하겠다" / "AI가 나를 대체할 것 같아 불안하다" / "말해봤자 아무것도 안 바뀐다" / "내가 여기서 성장하고 있는지 모르겠다"'),
  ...space(1),

  body('이 언어로 경영진에게 보고하면 즉각적인 인식이 일어난다. "이게 우리 조직 얘기구나." 그 인식이 바로 시스템의 정당성을 만드는 첫 번째 순간이다.'),

  divider(),

  // ═══ PART 4: 전체 EX Full Inventory ═══
  h1('4. 발견: 구성원 경험의 전체 지도'),
  label('EX Intelligence Full Inventory — 8개 현실 이슈 클러스터'),
  body('이론과 현실을 교차 검증하여 도출한 전체 측정 영역은 여덟 개 이슈 클러스터로 정리된다. 이 클러스터들은 독립적인 카테고리가 아니라, 구성원 경험이라는 하나의 유기체를 서로 다른 각도에서 바라보는 렌즈다.'),

