{"language": "bash", "code": "cat << 'SCRIPT' > /home/claude/build_essay.js
const { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType,
        BorderStyle, PageNumber, Footer, TabStopType, TabStopPosition,
        LevelFormat, ShadingType, WidthType, TableRow, TableCell, Table } = require('docx');
const fs = require('fs');

// ── 색상 상수 ─────────────────────────────────────────────────
const NAVY   = '1B2A4A';
const BLUE   = '2A5FA5';
const CORAL  = 'C0392B';
const GRAY   = '5F6368';
const LGRAY  = 'F4F4F2';
const MID    = 'D8D8D4';
const WHITE  = 'FFFFFF';

// ── 헬퍼: 단락 ───────────────────────────────────────────────
function body(text, opts = {}) {
  return new Paragraph({
    alignment: AlignmentType.JUSTIFIED,
    spacing: { after: 160, line: 340 },
    children: [new TextRun({
      text, font: 'Georgia', size: 24,
      color: opts.color || '1a1a1a',
      bold: opts.bold || false,
      italics: opts.italic || false,
    })]
  });
}

function quote(text) {
  return new Paragraph({
    alignment: AlignmentType.JUSTIFIED,
    spacing: { before: 120, after: 120, line: 320 },
    indent: { left: 720, right: 360 },
    border: { left: { style: BorderStyle.SINGLE, size: 18, color: CORAL, space: 12 } },
    children: [new TextRun({ text, font: 'Georgia', size: 22, italics: true, color: CORAL })]
  });
}

function space(n = 1) {
  return Array.from({ length: n }, () => new Paragraph({
    spacing: { after: 0, before: 0, line: 240 },
    children: [new TextRun({ text: '', size: 24 })]
  }));
}

function divider() {
  return new Paragraph({
    spacing: { before: 200, after: 200 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 4, color: MID, space: 1 } },
    children: [new TextRun({ text: '', size: 4 })]
  });
}

function label(text) {
  return new Paragraph({
    spacing: { before: 320, after: 80 },
    children: [new TextRun({
      text: text.toUpperCase(),
      font: 'Arial', size: 18, bold: true,
      color: BLUE, characterSpacing: 60
    })]
  });
}

function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 480, after: 160 },
    children: [new TextRun({ text, font: 'Arial', size: 36, bold: true, color: NAVY })]
  });
}

function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 320, after: 120 },
    children: [new TextRun({ text, font: 'Arial', size: 28, bold: true, color: BLUE })]
  });
}

function bullet(text, bold_prefix = '') {
  const children = [];
  if (bold_prefix) {
    children.push(new TextRun({ text: bold_prefix + ' ', font: 'Georgia', size: 24, bold: true, color: NAVY }));
    children.push(new TextRun({ text, font: 'Georgia', size: 24, color: '1a1a1a' }));
  } else {
    children.push(new TextRun({ text, font: 'Georgia', size: 24, color: '1a1a1a' }));
  }
  return new Paragraph({
    numbering: { reference: 'bullets', level: 0 },
    spacing: { after: 100, line: 320 },
    children
  });
}

