{"language": "bash", "code": "cat << 'SCRIPT' > /home/claude/build_roadmap.js
const { Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
        HeadingLevel, AlignmentType, BorderStyle, WidthType, ShadingType,
        VerticalAlign, PageNumber, Footer, LevelFormat } = require('docx');
const fs = require('fs');

// ── 색상 ─────────────────────────────────────────────────────
const NAVY   = '1B2A4A';
const BLUE   = '2A5FA5';
const CORAL  = 'C0392B';
const TEAL   = '0F6E56';
const AMBER  = '854F0B';
const GRAY   = '5F6368';
const LGRAY  = 'F4F4F4';
const MID    = 'D8D8D4';
const WHITE  = 'FFFFFF';

const STATUS = {
  done:  { bg: 'E1F5EE', fg: '0F6E56', label: '완료' },
  doing: { bg: 'E6F1FB', fg: '185FA5', label: '진행' },
  plan:  { bg: 'FAEEDA', fg: '854F0B', label: '예정' },
};

// ── 헬퍼 ──────────────────────────────────────────────────────
const bdr = (color = MID, sz = 4) => ({
  style: BorderStyle.SINGLE, size: sz, color
});
const noBdr = () => ({ style: BorderStyle.NONE, size: 0, color: WHITE });
const allBdr = (c, s = 4) => ({ top: bdr(c,s), bottom: bdr(c,s), left: bdr(c,s), right: bdr(c,s) });
const cellMgn = { top: 100, bottom: 100, left: 140, right: 140 };

function body(text, opts = {}) {
  return new Paragraph({
    alignment: AlignmentType.JUSTIFIED,
    spacing: { after: opts.after ?? 160, line: 340 },
    children: [new TextRun({
      text, font: 'Georgia', size: 23,
      color: opts.color || '1a1a1a',
      bold: opts.bold || false,
      italics: opts.italic || false,
    })]
  });
}

function sp(h = 1) {
  return Array.from({ length: h }, () =>
    new Paragraph({ spacing: { after: 0, line: 240 }, children: [new TextRun('')] })
  );
}

function divider(color = MID) {
  return new Paragraph({
    spacing: { before: 180, after: 180 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 4, color, space: 1 } },
    children: [new TextRun({ text: '', size: 4 })]
  });
}

function sectionLabel(text) {
  return new Paragraph({
    spacing: { before: 320, after: 80 },
    children: [new TextRun({
      text: text.toUpperCase(), font: 'Arial', size: 17,
      bold: true, color: BLUE, characterSpacing: 60
    })]
  });
}

function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 400, after: 140 },
    children: [new TextRun({ text, font: 'Arial', size: 34, bold: true, color: NAVY })]
  });
}

function h2(text, color = BLUE) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 260, after: 100 },
    children: [new TextRun({ text, font: 'Arial', size: 26, bold: true, color })]
  });
}

function h3(text, color = NAVY) {
  return new Paragraph({
    spacing: { before: 200, after: 80 },
    children: [new TextRun({ text, font: 'Arial', size: 22, bold: true, color })]
  });
}

function quoteBlock(text, color = CORAL) {
  return new Paragraph({
    alignment: AlignmentType.JUSTIFIED,
    spacing: { before: 100, after: 100, line: 320 },
    indent: { left: 680, right: 340 },
    border: { left: { style: BorderStyle.SINGLE, size: 18, color, space: 12 } },
    children: [new TextRun({ text, font: 'Georgia', size: 22, italics: true, color })]
  });
}

function bullet(text, boldPart = '') {
  const children = boldPart
    ? [new TextRun({ text: boldPart + ' ', font: 'Georgia', size: 23, bold: true, color: NAVY }),
       new TextRun({ text, font: 'Georgia', size: 23, color: '1a1a1a' })]
    : [new TextRun({ text, font: 'Georgia', size: 23, color: '1a1a1a' })];
  return new Paragraph({
    numbering: { reference: 'bullets', level: 0 },
    spacing: { after: 90, line: 320 },
    children
  });
}

function subBullet(text) {
  return new Paragraph({
    numbering: { reference: 'subbullets', level: 0 },
    spacing: { after: 70, line: 300 },
    children: [new TextRun({ text, font: 'Georgia', size: 21, color: GRAY })]
  });
}

