// ── 산출물 카드 테이블 ────────────────────────────────────────
function outputCard(items) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [4580, 4780],
    rows: chunkPairs(items).map(pair =>
      new TableRow({
        children: pair.map(item => new TableCell({
          borders: allBdr(item ? MID : LGRAY),
          shading: { fill: item ? 'F7F9FC' : LGRAY, type: ShadingType.CLEAR },
          margins: { top: 120, bottom: 120, left: 160, right: 160 },
          children: item ? [
            new Paragraph({
              spacing: { after: 40 },
              children: [new TextRun({ text: item.icon + '  ' + item.title, font: 'Arial', size: 21, bold: true, color: BLUE })]
            }),
            new Paragraph({
              children: [new TextRun({ text: item.desc, font: 'Georgia', size: 20, color: GRAY })]
            })
          ] : [new Paragraph({ children: [new TextRun('')] })]
        }))
      })
    )
  });
}

function chunkPairs(arr) {
  const pairs = [];
  for (let i = 0; i < arr.length; i += 2)
    pairs.push([arr[i], arr[i+1] || null]);
  return pairs;
}

// ── 의사결정 포인트 테이블 ────────────────────────────────────
