              children: [new TextRun({ text: h, font: 'Arial', size: 20, bold: true, color: WHITE })]
            })]
          })
        )
      }),
      ...rows.map(([item, a, b], i) =>
        new TableRow({
          children: [item, a, b].map((v, j) =>
            new TableCell({
              borders: allBdr(MID),
              shading: { fill: i % 2 === 0 ? LGRAY : WHITE, type: ShadingType.CLEAR },
              margins: cellMgn,
              children: [new Paragraph({
                alignment: j === 0 ? AlignmentType.LEFT : AlignmentType.CENTER,
                children: [new TextRun({ text: v, font: j === 0 ? 'Arial' : 'Georgia', size: 20,
                  bold: j === 0, color: j === 0 ? NAVY : '1a1a1a' })]
              })]
            })
