function sp(n = 1) {
  return Array.from({ length: n }, () =>
    new Paragraph({ spacing: { after: 0, line: 240 }, children: [new TextRun('')] })
  );
}

function para(text, opts = {}) {
  return new Paragraph({
    alignment: opts.align || AlignmentType.LEFT,
    spacing: { after: opts.after ?? 120, line: opts.line || 320 },
    indent: opts.indent ? { left: opts.indent } : undefined,
    border: opts.leftBorder ? { left: { style: BorderStyle.SINGLE, size: 18, color: opts.leftBorder, space: 10 } } : undefined,
