// ── 클러스터 헤더 ─────────────────────────────────────────
function clusterHeader(code, headline, sub, isNew = false) {
  const bg = isNew ? 'FFF8EC' : 'F0F4FA';
  const bc = isNew ? NEW : BLUE;
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [800, 6960, 1600],
    rows: [new TableRow({
      children: [
        new TableCell({
          borders: allBdr(bc, 6),
          shading: { fill: bc, type: ShadingType.CLEAR },
          margins: cm2,
          verticalAlign: VerticalAlign.CENTER,
          children: [new Paragraph({ alignment: AlignmentType.CENTER,
            children: [new TextRun({ text: code, font: 'Arial', size: 22, bold: true, color: WHITE })] })]
        }),
        new TableCell({
          borders: allBdr(bc, 6),
          shading: { fill: bg, type: ShadingType.CLEAR },
          margins: { top: 100, bottom: 100, left: 200, right: 140 },
          children: [
            new Paragraph({ spacing: { after: 30 },
              children: [new TextRun({ text: `"${headline}"`, font: 'Arial', size: 24, bold: true, color: NAVY })] }),
            new Paragraph({ children: [new TextRun({ text: sub, font: 'Georgia', size: 20, italics: true, color: GRAY })] }),
          ]
        }),
        new TableCell({
          borders: allBdr(bc, 6),
          shading: { fill: isNew ? NEW : NAVY, type: ShadingType.CLEAR },
          margins: cm2,
          verticalAlign: VerticalAlign.CENTER,
          children: [new Paragraph({ alignment: AlignmentType.CENTER,
            children: [new TextRun({ text: isNew ? '★ 신규' : '기존', font: 'Arial', size: 18, bold: true, color: WHITE })] })]
        }),
      ]
    })]
  });
}

// ── 현장 신호 블록 ────────────────────────────────────────
function signalBlock(signals) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [1400, 7960],
    rows: [
      new TableRow({ children: [
        new TableCell({ borders: allBdr(MID), shading: { fill: LGRAY, type: ShadingType.CLEAR }, margins: cm,
          verticalAlign: VerticalAlign.CENTER,
          children: [new Paragraph({ children: [new TextRun({ text: '현장 신호', font: 'Arial', size: 19, bold: true, color: NAVY })] })] }),
        new TableCell({ borders: allBdr(MID), shading: { fill: WHITE, type: ShadingType.CLEAR }, margins: cm,
          children: signals.map(s => new Paragraph({ spacing: { after: 50 },
            children: [new TextRun({ text: '· ' + s, font: 'Georgia', size: 21, color: '1a1a1a' })] })) }),
      ]}),
    ]
  });
}

// ── 키워드 블록 ───────────────────────────────────────────
function keywordBlock(keywords) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [1400, 7960],
    rows: [new TableRow({ children: [
      new TableCell({ borders: allBdr(MID), shading: { fill: LGRAY, type: ShadingType.CLEAR }, margins: cm,
        verticalAlign: VerticalAlign.CENTER,
        children: [new Paragraph({ children: [new TextRun({ text: '핵심 키워드', font: 'Arial', size: 19, bold: true, color: NAVY })] })] }),
      new TableCell({ borders: allBdr(MID), shading: { fill: WHITE, type: ShadingType.CLEAR }, margins: cm,
        children: [new Paragraph({ children: [new TextRun({ text: keywords.join('  ·  '), font: 'Georgia', size: 21, color: BLUE })] })] }),
    ]})]
  });
}

// ── 측정방식 테이블 ───────────────────────────────────────
function measureTable(pulse, deep, behav, dialog) {
  const cols = [
    { label: '펄스', items: pulse, color: '534AB7', bg: 'EEEDFE' },
    { label: '심층', items: deep,  color: '0F6E56', bg: 'E1F5EE' },
    { label: '행동데이터', items: behav, color: '854F0B', bg: 'FAEEDA' },
    { label: '대화', items: dialog, color: '993C1D', bg: 'FAECE7' },
  ];
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [1400, 1990, 1990, 1990, 1990],
    rows: [
      new TableRow({ children: [
        new TableCell({ borders: allBdr(MID), shading: { fill: LGRAY, type: ShadingType.CLEAR }, margins: cm,
          verticalAlign: VerticalAlign.CENTER,
          children: [new Paragraph({ children: [new TextRun({ text: '측정 방식', font: 'Arial', size: 19, bold: true, color: NAVY })] })] }),
        ...cols.map(c => new TableCell({
          borders: allBdr(MID),
          shading: { fill: c.items.length ? c.bg : LGRAY, type: ShadingType.CLEAR },
          margins: cm,
          children: [
            new Paragraph({ spacing: { after: 30 }, alignment: AlignmentType.CENTER,
              children: [new TextRun({ text: c.label, font: 'Arial', size: 18, bold: true,
                color: c.items.length ? c.color : 'AAAAAA' })] }),
            ...c.items.map(i => new Paragraph({ alignment: AlignmentType.CENTER,
              children: [new TextRun({ text: i, font: 'Georgia', size: 18,
                color: c.items.length ? c.color : 'BBBBBB' })] })),
            ...(c.items.length === 0 ? [new Paragraph({ alignment: AlignmentType.CENTER,
              children: [new TextRun({ text: '—', font: 'Arial', size: 18, color: 'CCCCCC' })] })] : []),
          ]
        }))
      ]})
    ]
  });
}

// ── 노트 블록 ─────────────────────────────────────────────
function noteBlock(label, text, color = CORAL) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [1400, 7960],
    rows: [new TableRow({ children: [
      new TableCell({ borders: allBdr(color, 4), shading: { fill: color, type: ShadingType.CLEAR }, margins: cm,
        verticalAlign: VerticalAlign.CENTER,
        children: [new Paragraph({ alignment: AlignmentType.CENTER,
          children: [new TextRun({ text: label, font: 'Arial', size: 17, bold: true, color: WHITE })] })] }),
      new TableCell({ borders: allBdr(color, 4), shading: { fill: WHITE, type: ShadingType.CLEAR }, margins: cm,
        children: [new Paragraph({ children: [new TextRun({ text, font: 'Georgia', size: 20, italics: true, color: '333333' })] })] }),
    ]})]
  });
}

// ── 클러스터 전체 블록 ────────────────────────────────────
function cluster(code, headline, sub, isNew, signals, keywords, pulse, deep, behav, dialog, notes = []) {
  return [
    clusterHeader(code, headline, sub, isNew),
    ...sp(1),
    signalBlock(signals),
    ...sp(1),
    keywordBlock(keywords),
    ...sp(1),
    measureTable(pulse, deep, behav, dialog),
    ...(notes.map(([label, text, color]) => [
      ...sp(1),
      noteBlock(label, text, color)
    ]).flat()),
    ...sp(2),
    divider(),
    ...sp(1),
  ];
}

