            shading: { fill: layer ? (i < 4 ? 'E6F1FB' : i < 8 ? 'E1F5EE' : 'FAECE7') : WHITE, type: ShadingType.CLEAR },
            margins: cm,
            children: [new Paragraph({ alignment: AlignmentType.CENTER,
              children: [new TextRun({ text: layer, font: 'Arial', size: 18, bold: !!layer,
                color: layer ? (i < 4 ? BLUE : i < 8 ? TEAL : CORAL) : WHITE })] })] }),
          new TableCell({ borders: allBdr(MID), shading: { fill: isNew ? 'FFF8EC' : LGRAY, type: ShadingType.CLEAR }, margins: cm,
            children: [new Paragraph({ alignment: AlignmentType.CENTER,
              children: [new TextRun({ text: code, font: 'Arial', size: 18, bold: true,
                color: isNew ? NEW : BLUE })] })] }),
          new TableCell({ borders: allBdr(MID), shading: { fill: WHITE, type: ShadingType.CLEAR }, margins: cm,
            children: [new Paragraph({ children: [new TextRun({ text: name, font: 'Georgia', size: 19,
                color: isNew ? NEW : '1a1a1a', bold: isNew })] })] }),
          new TableCell({ borders: allBdr(MID), shading: { fill: WHITE, type: ShadingType.CLEAR }, margins: cm,
            children: [new Paragraph({ children: [new TextRun({ text: priority, font: 'Georgia', size: 18, color: GRAY })] })] }),
          new TableCell({ borders: allBdr(isNew ? NEW : MID),
            shading: { fill: isNew ? 'FFF8EC' : WHITE, type: ShadingType.CLEAR }, margins: cm,
            children: [new Paragraph({ alignment: AlignmentType.CENTER,
