                bold: isNew, color: isNew ? NEW : GRAY })] })] }),
        ]});
      })
    ]
  });
}

// ── 결론 블록 ─────────────────────────────────────────────
function conclusionBlock() {
  return [
    new Paragraph({ spacing: { before: 200, after: 100 },
      children: [new TextRun({ text: '결론 및 시사점', font: 'Arial', size: 28, bold: true, color: NAVY })] }),
    divider(NAVY),
    ...sp(1),
    new Table({
      width: { size: 9360, type: WidthType.DXA },
      columnWidths: [9360],
      rows: [[
        ['기존 8개  →  보완 3개 추가  →  총 11개 클러스터'],
