        ['펄스 대상은 11개 중 9개 클러스터, 실제 문항은 7개 이내로 압축.'],
      ].map((line, idx) =>
        new TableRow({ children: [new TableCell({
          borders: allBdr('1B2A4A', 6),
          shading: { fill: idx === 0 ? 'F0F4FA' : WHITE, type: ShadingType.CLEAR },
          margins: { top: idx === 0 ? 140 : 60, bottom: idx === 0 ? 140 : 60, left: 200, right: 200 },
          children: [new Paragraph({ children: [new TextRun({
            text: line[0], font: idx === 0 ? 'Arial' : 'Georgia',
            size: idx === 0 ? 22 : 20, bold: idx === 0,
            color: idx === 0 ? NAVY : (line[0].startsWith('I0') || line[0].startsWith('I1') ? NEW : '333333'),
          })] })]
        })] })
      )]
    }),
  ];
}

// ══════════════════════════════════════════════════════════
// 문서 조립
// ══════════════════════════════════════════════════════════
