  box-shadow: 0 2px 40px rgba(0,0,0,.07), 0 1px 4px rgba(0,0,0,.04);
  animation: fadeIn .8s ease both;
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(20px); }
  to   { opacity: 1; transform: translateY(0); }
}

/* 상단 레터헤드 */
.letterhead {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  margin-bottom: 52px;
  padding-bottom: 28px;
  border-bottom: 1px solid #E0DBD3;
}
.lh-from {
  display: flex;
  flex-direction: column;
  gap: 3px;
}
.lh-label {
  font-family: 'DM Mono', monospace;
  font-size: 10px;
  color: #B0A898;
  letter-spacing: .14em;
  text-transform: uppercase;
}
.lh-name {
  font-family: 'Noto Serif KR', serif;
  font-size: 15px;
  font-weight: 600;
  color: #2C2416;
}
.lh-date {
  font-family: 'DM Mono', monospace;
  font-size: 11px;
  color: #B0A898;
  letter-spacing: .06em;
  text-align: right;
  line-height: 1.8;
}

/* 수신 */
.to-block {
  margin-bottom: 36px;
}
.to-label {
  font-family: 'DM Mono', monospace;
  font-size: 10px;
  color: #B0A898;
  letter-spacing: .14em;
  text-transform: uppercase;
  margin-bottom: 5px;
}
.to-name {
  font-family: 'Noto Serif KR', serif;
  font-size: 18px;
  font-weight: 700;
  color: #1B2A4A;
}
.to-dept {
  font-size: 13px;
  color: #8A8070;
  margin-top: 2px;
  font-weight: 300;
}

/* 인사말 */
.salutation {
  font-size: 16px;
  color: #2C2416;
  line-height: 1.9;
  margin-bottom: 28px;
}

/* 본문 */
.body-text {
  font-size: 16px;
  color: #2C2416;
  line-height: 2.1;
  margin-bottom: 24px;
  font-weight: 300;
}

/* 강조 문장 */
.emphasis {
  margin: 36px 0;
  padding: 24px 28px;
  border-left: 3px solid #C0392B;
  background: rgba(192,57,43,.03);
}
.emphasis p {
  font-size: 17px;
  font-weight: 400;
  color: #2C2416;
  line-height: 2.1;
}
.emphasis .strike {
  color: #B0A898;
  text-decoration: line-through;
}
.emphasis .bold-blue {
  color: #1B2A4A;
  font-weight: 700;
}

/* 처방 인라인 */
.rx-inline {
  display: inline;
  background: rgba(42,157,143,.08);
  border-radius: 3px;
  padding: 1px 6px;
  color: #0F6E56;
  font-weight: 600;
}

/* 서명 */
.sign-block {
  margin-top: 56px;
  padding-top: 32px;
  border-top: 1px solid #E0DBD3;
}
.sign-closing {
  font-size: 15px;
  color: #2C2416;
  margin-bottom: 20px;
  font-weight: 300;
}
.sign-name {
  font-family: 'Noto Serif KR', serif;
  font-size: 15px;
  font-weight: 600;
  color: #1B2A4A;
  margin-bottom: 3px;
}
.sign-role {
  font-family: 'DM Mono', monospace;
  font-size: 10px;
  color: #B0A898;
  letter-spacing: .1em;
}

/* 하단 스탬프 */
.stamp {
  margin-top: 36px;
  text-align: right;
}
.stamp-inner {
  display: inline-block;
  border: 1.5px solid rgba(192,57,43,.25);
  border-radius: 4px;
  padding: 6px 14px;
  font-family: 'DM Mono', monospace;
  font-size: 10px;
  color: rgba(192,57,43,.45);
  letter-spacing: .1em;
  text-transform: uppercase;
}
</style>
</head>
<body>

<div class="letter">

  <!-- 레터헤드 -->
  <div class="letterhead">
    <div class="lh-from">
      <span class="lh-label">From</span>
      <span class="lh-name">EX Intelligence · Coaching Agent</span>
    </div>
    <div class="lh-date">
      2026년 4월<br>
      1:1 맞춤 스크립트
    </div>
  </div>

  <!-- 수신 -->
  <div class="to-block">
    <div class="to-label">To</div>
    <div class="to-name">송시용 상무님께</div>
    <div class="to-dept">Smart Factory Biz</div>
  </div>

  <!-- 본문 -->
  <p class="salutation">
    상무님,
  </p>

  <p class="body-text">
    이번 2,000억 수주 성과는 생산기술원 역사에 남을 만한 업적입니다.<br>
    진심으로 축하드립니다.
  </p>

  <p class="body-text">
    그런데, 한 가지만 여쭤봐도 될까요.
  </p>

  <p class="body-text">
    상무님이 없는 자리에 남겨진 구성원들의 표정을<br>
    한번만 더 봐주세요.
  </p>

  <div class="emphasis">
    <p>
      이제는 <span class="strike">'무엇을(What)' 달성할 것인가</span>보다<br>
      <span class="bold-blue">'어떻게(How)' 그들과 함께 끝까지 달릴 것인가</span>를<br>
      더 고민해야 할 때입니다.
    </p>
  </div>

  <p class="body-text">
    비결은 어렵지 않습니다.<br>
    <span class="rx-inline">감사 표현</span>과 <span class="rx-inline">적극적 경청</span>의 단 5분입니다.
  </p>

  <p class="body-text">
    오늘 하루, 구성원 한 명의 이름을 부르며<br>
    "고생했어요"라는 말 한마디를 건네보시겠습니까.
  </p>

  <!-- 서명 -->
  <div class="sign-block">
    <p class="sign-closing">따뜻한 마음을 담아,</p>
    <div class="sign-name">EX Intelligence</div>
    <div class="sign-role">Coaching Agent · 1:1 Personalized Script</div>
  </div>

  <!-- 스탬프 -->
  <div class="stamp">
    <div class="stamp-inner">Confidential · For Leader Only</div>
  </div>

</div>

</body>
</html>
