<title>Coaching Card Letter</title>
<link href="https://fonts.googleapis.com/css2?family=Noto+Serif+KR:wght@300;400;600;700&family=Noto+Sans+KR:wght@300;400;500&family=DM+Mono:wght@400;500&display=swap" rel="stylesheet">
<style>
* { box-sizing: border-box; margin: 0; padding: 0; }

body {
  background: #ECEAE4;
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 48px 20px;
  font-family: 'Noto Serif KR', serif;
}

/* 카드 전체 */
.card {
  max-width: 480px;
  width: 100%;
  animation: rise .7s cubic-bezier(.22,.61,.36,1) both;
}
@keyframes rise {
  from { opacity: 0; transform: translateY(28px); }
  to   { opacity: 1; transform: translateY(0); }
}

/* 상단 컬러 밴드 */
.card-band {
  background: #1B2A4A;
  border-radius: 16px 16px 0 0;
  padding: 22px 32px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}
.band-label {
  font-family: 'DM Mono', monospace;
  font-size: 10px;
  color: rgba(255,255,255,.4);
  letter-spacing: .16em;
  text-transform: uppercase;
}
.band-to {
  font-family: 'Noto Serif KR', serif;
  font-size: 13px;
  color: rgba(255,255,255,.75);
  font-weight: 300;
}

/* 카드 본체 */
.card-body {
  background: #FDFBF7;
  border-radius: 0 0 16px 16px;
  padding: 40px 36px 36px;
  box-shadow: 0 8px 40px rgba(0,0,0,.10), 0 2px 8px rgba(0,0,0,.06);
}

/* 성과 칩 */
.achievement-chip {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  background: #FDF6E3;
  border: 1px solid #E8D48A;
  border-radius: 999px;
  padding: 6px 14px 6px 10px;
  margin-bottom: 28px;
}
.chip-dot {
  width: 7px; height: 7px;
  border-radius: 50%;
  background: #C9A227;
  flex-shrink: 0;
}
.chip-text {
  font-family: 'DM Mono', monospace;
  font-size: 11px;
  color: #8A6A00;
  letter-spacing: .04em;
}

/* 본문 텍스트 */
.para {
  font-size: 15.5px;
  font-weight: 300;
  color: #2C2416;
  line-height: 2.05;
  margin-bottom: 20px;
}
.para:last-of-type { margin-bottom: 0; }

/* 중간 구분선 */
.rule {
  height: 1px;
  background: #E5E0D8;
  margin: 26px 0;
}

/* 핵심 전환 강조 */
.pivot {
  font-size: 15.5px;
  font-weight: 300;
  color: #2C2416;
  line-height: 2.05;
  margin-bottom: 20px;
}
.pivot .from {
  color: #A89880;
}
.pivot .to {
  color: #1B2A4A;
  font-weight: 600;
}

/* 처방 박스 */
.rx-box {
  margin: 26px 0 24px;
  background: #F2F8F6;
  border-left: 3px solid #0F6E56;
  border-radius: 0 8px 8px 0;
  padding: 16px 20px;
}
.rx-text {
  font-size: 15px;
  color: #0F4A38;
  line-height: 1.9;
  font-weight: 400;
}
.rx-text strong {
  font-weight: 600;
}

/* 서명 */
.sign {
  margin-top: 32px;
  padding-top: 24px;
  border-top: 1px solid #E5E0D8;
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
}
.sign-closing {
  font-size: 14px;
  color: #8A8070;
  font-weight: 300;
  line-height: 1.8;
}
.sign-from {
  text-align: right;
}
.sign-name {
  font-family: 'DM Mono', monospace;
  font-size: 10px;
  color: #B0A898;
  letter-spacing: .1em;
  text-transform: uppercase;
  line-height: 1.8;
}
</style>
</head>
