<!DOCTYPE html>
<html lang="ko">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>구성원 경험 전체 지도 — The EX Map</title>
<link href="https://fonts.googleapis.com/css2?family=Noto+Serif+KR:wght@300;400;600;700&family=Noto+Sans+KR:wght@300;400;500;700&family=DM+Mono:wght@400;500&display=swap" rel="stylesheet">
<style>
* { box-sizing: border-box; margin: 0; padding: 0; }

body {
  background: #F5F2ED;
  font-family: 'Noto Sans KR', sans-serif;
  padding: 48px 32px;
  min-width: 1200px;
}

/* ── 전체 래퍼 ── */
.page {
  max-width: 1280px;
  margin: 0 auto;
  background: #FDFBF8;
  border-radius: 16px;
  padding: 52px 60px 56px;
  box-shadow: 0 4px 40px rgba(0,0,0,.08);
}

/* ── 헤더 ── */
.header {
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
  margin-bottom: 48px;
  padding-bottom: 28px;
  border-bottom: 1.5px solid #E5E0D8;
}
.header-left {}
.header-tag {
  font-family: 'DM Mono', monospace;
  font-size: 11px;
  color: #B0A898;
  letter-spacing: .16em;
  text-transform: uppercase;
  margin-bottom: 8px;
}
.header-title {
  font-family: 'Noto Serif KR', serif;
  font-size: 32px;
  font-weight: 700;
  color: #1B2A4A;
  line-height: 1.2;
}
.header-title span {
  font-size: 18px;
  font-weight: 300;
  color: #8A8070;
  margin-left: 8px;
}
.header-legend {
  display: flex;
  gap: 20px;
  align-items: center;
}
.legend-item {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 11px;
  color: #8A8070;
}
.legend-dot {
  width: 8px; height: 8px;
  border-radius: 50%;
}

/* ── 메인 그리드 ── */
.main-grid {
  display: grid;
  grid-template-columns: 130px 1fr;
  gap: 0;
}

/* ── 레이어 레이블 ── */
.layer-labels {
  display: flex;
  flex-direction: column;
  gap: 0;
  padding-right: 0;
}
.layer-label-cell {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  padding-right: 20px;
}
.layer-badge {
  text-align: right;
}
.layer-no {
  font-family: 'DM Mono', monospace;
  font-size: 10px;
  font-weight: 500;
  letter-spacing: .1em;
  text-transform: uppercase;
  margin-bottom: 3px;
}
.layer-name {
  font-size: 12px;
  font-weight: 700;
  margin-bottom: 2px;
}
.layer-sub {
  font-size: 10px;
  color: #A89880;
  font-weight: 300;
}

/* ── 레이어 콘텐츠 ── */
.layer-content {
  display: flex;
  flex-direction: column;
  gap: 0;
}
.layer-row {
  display: flex;
  align-items: stretch;
  border-radius: 12px;
  padding: 20px 20px 20px 24px;
  margin-bottom: 10px;
  position: relative;
}
.layer-row:last-child { margin-bottom: 0; }

.l1-row { background: #EEF4FB; border: 1px solid #C8DDF4; }
.l2-row { background: #EBF7F2; border: 1px solid #A8DCC8; }
.l3-row { background: #FDF0EB; border: 1px solid #F0C4B0; }

/* ── 클러스터 카드 ── */
.clusters-wrap {
  flex: 1;
  display: flex;
  gap: 10px;
  align-items: stretch;
}
.cluster-card {
  flex: 1;
  background: #fff;
  border-radius: 10px;
  border: 1px solid rgba(0,0,0,.07);
  padding: 14px 14px 12px;
  display: flex;
  flex-direction: column;
  min-width: 0;
  position: relative;
}
.cluster-card.is-new {
  border-width: 1.5px;
}
.new-star {
  position: absolute;
  top: -8px; right: 10px;
  font-size: 13px;
  line-height: 1;
}
.c-id {
  font-family: 'DM Mono', monospace;
  font-size: 10px;
  font-weight: 500;
  margin-bottom: 4px;
}
.c-name {
  font-size: 12px;
  font-weight: 700;
  color: #1B2A4A;
  line-height: 1.4;
  margin-bottom: 6px;
}
.c-voice {
  font-family: 'Noto Serif KR', serif;
  font-size: 12px;
  font-style: italic;
  color: #5A5040;
  line-height: 1.55;
  margin-bottom: 10px;
  flex: 1;
}
.c-methods {
  display: flex;
  gap: 4px;
